import { useState, useEffect } from "react";
import { recipeAPI } from "../../services/api";
import CreateRecipeModal from "../../components/CreateRecipeModal";

const NAV = [
  { icon: "🏠", label: "Feed", id: "feed" },
  { icon: "👨‍🍳", label: "My Creations", id: "creations" },
  { icon: "📈", label: "Analytics", id: "analytics" },
];

const TABS = ["All Recipes", "Live", "Pending Review", "Rejected"];

const STATUS_BADGE = {
  Live: "badge-live",
  "Pending Review": "badge-pending",
  Rejected: "badge-rejected",
};

export default function ChefDashboardPage({ setPage, setSelectedRecipe, user }) {
  const [activeNav, setActiveNav] = useState("feed");
  const [activeTab, setActiveTab] = useState("All Recipes");
  const [recipes, setRecipes] = useState([]);
  const [feedRecipes, setFeedRecipes] = useState([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [loading, setLoading] = useState(false);

  const displayName = user?.name ? user.name : "Chef";
  const displayRole = user?.role ? `${user.role.charAt(0).toUpperCase()}${user.role.slice(1)}` : "Chef";

  const sectionTitles = {
    feed: "Recipe Feed",
    creations: "My Creations",
    analytics: "Analytics",
  };

  useEffect(() => {
    if (activeNav === "creations") {
      fetchMyRecipes();
    } else if (activeNav === "feed") {
      fetchFeed();
    }
  }, [activeNav]);

  const fetchMyRecipes = async () => {
    try {
      setLoading(true);
      const response = await recipeAPI.getMyRecipes();
      if (response.data.success) {
        setRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching chef recipes:", err);
    } finally {
      setLoading(false);
    }
  };

  const fetchFeed = async () => {
    try {
      setLoading(true);
      const response = await recipeAPI.getAll({ limit: 20 });
      if (response.data.success) {
        setFeedRecipes(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching feed:", err);
    } finally {
      setLoading(false);
    }
  };

  const filtered = activeTab === "All Recipes" 
    ? recipes 
    : recipes.filter(r => r.status === activeTab);

  return (
    <div className="sidebar-layout">
      {/* SIDEBAR */}
      <aside className="sidebar">
        <div style={{ padding: "0 8px 32px" }}>
          <div style={{ display: "flex", alignItems: "center", gap: "10px", marginBottom: "32px" }}>
            <div style={{ width: "32px", height: "32px", background: "var(--primary)", borderRadius: "8px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "16px", color: "#fff" }}>🍽</div>
            <span className="serif" style={{ fontSize: "18px", fontWeight: "700", color: "var(--navy)" }}>RecipeNest</span>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: "4px" }}>
            {NAV.map(item => (
              <button 
                key={item.id} 
                className={`sidebar-item ${activeNav === item.id ? "active" : ""}`} 
                onClick={() => setActiveNav(item.id)}
              >
                <span style={{ fontSize: "18px" }}>{item.icon}</span>
                {item.label}
              </button>
            ))}
          </div>
        </div>

        <div style={{ marginTop: "auto", padding: "20px 8px 0", borderTop: "1px solid var(--border-light)" }}>
          <button className="sidebar-item" style={{ marginBottom: "16px" }}>
            <span style={{ fontSize: "18px" }}>⚙️</span> Settings
          </button>

          <div style={{ display: "flex", alignItems: "center", gap: "12px", padding: "12px", background: "var(--bg)", borderRadius: "var(--radius-md)", marginBottom: "16px", border: "1px solid var(--border-light)" }}>
            <div className="sidebar-avatar" style={{ width: "40px", height: "40px", fontSize: "14px", fontWeight: "700", background: "var(--primary)", color: "#fff", display: "flex", alignItems: "center", justifyContent: "center", borderRadius: "10px" }}>
              {displayName.split(" ").map(x => x[0]).join("").slice(0, 2).toUpperCase()}
            </div>
            <div>
              <div style={{ fontSize: "13px", fontWeight: "700", color: "var(--text-main)" }}>{displayName}</div>
              <div style={{ fontSize: "11px", color: "var(--text-muted)" }}>{displayRole}</div>
            </div>
          </div>

          <button className="logout-btn" onClick={() => setPage("home")}>
            <span>🚪</span> Logout
          </button>
        </div>
      </aside>

      {/* DASHBOARD CONTENT */}
      <main className="page-content" style={{ background: "var(--bg)" }}>
        <div className="page-header" style={{ marginBottom: "40px" }}>
          <div>
            <h1 className="page-title">{sectionTitles[activeNav] || "Dashboard"}</h1>
            <p className="page-sub">
              {activeNav === "feed" ? "Discover amazing recipes from the community" :
               activeNav === "creations" ? "Hi " + displayName + ", manage your recipe portfolio" :
               "Hi " + displayName + ", this is your " + displayRole + " dashboard"}
            </p>
          </div>
          {activeNav === "creations" && (
            <button 
              className="action-cta" 
              style={{ filter: "drop-shadow(0 4px 12px rgba(255, 49, 49, 0.2))" }}
              onClick={() => setIsModalOpen(true)}
            >
              <span style={{ fontSize: "18px" }}>+</span> Create New Recipe
            </button>
          )}
        </div>

        <>
        {activeNav === "feed" ? (
          // Feed View
          <div style={{ display: "flex", flexDirection: "column", gap: "24px" }}>
            {loading ? (
              <div style={{ textAlign: "center", padding: "40px" }}>
                <div style={{ 
                  width: "40px", 
                  height: "40px", 
                  border: "4px solid var(--border-light)", 
                  borderTop: "4px solid var(--primary)", 
                  borderRadius: "50%", 
                  animation: "spin 1s linear infinite",
                  margin: "0 auto 16px"
                }} />
                <p>Loading recipes...</p>
              </div>
            ) : (
              feedRecipes.map(recipe => (
                <div key={recipe._id} style={{ 
                  background: "var(--white)", 
                  borderRadius: "var(--radius-lg)", 
                  overflow: "hidden",
                  boxShadow: "var(--shadow-sm)",
                  border: "1px solid var(--border-light)"
                }}>
                  {/* Recipe Header */}
                  <div style={{ padding: "16px 20px", borderBottom: "1px solid var(--border-light)" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: "12px" }}>
                      <img 
                        src={recipe.chef?.avatar || "https://via.placeholder.com/40"} 
                        alt={recipe.chef?.name} 
                        style={{ width: "40px", height: "40px", borderRadius: "50%", objectFit: "cover" }}
                      />
                      <div>
                        <div style={{ fontWeight: "600", color: "var(--text-main)" }}>{recipe.chef?.name || "Chef"}</div>
                        <div style={{ fontSize: "12px", color: "var(--text-muted)" }}>
                          {new Date(recipe.createdAt).toLocaleDateString()}
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Recipe Image */}
                  <div style={{ position: "relative" }}>
                    <img 
                      src={recipe.image} 
                      alt={recipe.title} 
                      style={{ width: "100%", height: "300px", objectFit: "cover", cursor: "pointer" }}
                      onClick={() => {
                        setSelectedRecipe(recipe);
                        setPage("recipe-detail");
                      }}
                    />
                  </div>

                  {/* Recipe Content */}
                  <div style={{ padding: "16px 20px" }}>
                    <h3 style={{ fontSize: "18px", fontWeight: "700", marginBottom: "8px", cursor: "pointer" }}
                        onClick={() => {
                          setSelectedRecipe(recipe);
                          setPage("recipe-detail");
                        }}>
                      {recipe.title}
                    </h3>
                    <p style={{ color: "var(--text-muted)", fontSize: "14px", marginBottom: "16px" }}>
                      {recipe.description}
                    </p>

                    {/* Tags */}
                    <div style={{ display: "flex", gap: "8px", marginBottom: "16px" }}>
                      <span style={{ 
                        background: "var(--primary)", 
                        color: "white", 
                        padding: "4px 8px", 
                        borderRadius: "12px", 
                        fontSize: "12px",
                        fontWeight: "500"
                      }}>
                        {recipe.tag}
                      </span>
                      <span style={{ 
                        background: "var(--bg)", 
                        color: "var(--text-main)", 
                        padding: "4px 8px", 
                        borderRadius: "12px", 
                        fontSize: "12px",
                        fontWeight: "500"
                      }}>
                        {recipe.difficulty}
                      </span>
                    </div>

                    {/* Actions */}
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                      <div style={{ display: "flex", alignItems: "center", gap: "16px" }}>
                        <span style={{ fontSize: "14px", color: "var(--text-muted)" }}>
                          ❤️ {recipe.likes?.length || 0}
                        </span>
                        <span style={{ fontSize: "14px", color: "var(--text-muted)" }}>
                          🔖 {recipe.savedBy?.length || 0}
                        </span>
                      </div>
                      <button 
                        style={{ 
                          background: "var(--primary)", 
                          color: "white", 
                          border: "none", 
                          padding: "8px 16px", 
                          borderRadius: "20px", 
                          fontSize: "14px",
                          cursor: "pointer"
                        }}
                        onClick={() => {
                          setSelectedRecipe(recipe);
                          setPage("recipe-detail");
                        }}
                      >
                        View Recipe
                      </button>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>
        ) : activeNav === "creations" ? (
          <div>
            <>
              {/* Stats Row */}
            <div className="stats-row" style={{ marginBottom: "48px" }}>
              {[
                { label: "Total Recipes", val: recipes.length.toString(), icon: "📝", bg: "rgba(59, 130, 246, 0.1)", color: "#3b82f6" },
                { label: "Recipe Likes", val: "45.8k", icon: "❤️", bg: "rgba(239, 68, 68, 0.1)", color: "#ef4444" },
                { label: "Average Rating", val: "4.8", icon: "⭐", bg: "rgba(234, 179, 8, 0.1)", color: "#eab308" }
              ].map((stat, i) => (
                <div key={i} className="stat-card" style={{ border: "1px solid var(--border-light)", boxShadow: "var(--shadow-sm)" }}>
                  <div className="stat-icon" style={{ background: stat.bg, color: stat.color }}>{stat.icon}</div>
                  <div>
                    <div className="stat-val">{stat.val}</div>
                    <div className="stat-label">{stat.label}</div>
                  </div>
                </div>
              ))}
            </div>

            {/* Tabs */}
            <div className="tab-bar" style={{ marginBottom: "32px", borderBottom: "1px solid var(--border-light)" }}>
              {TABS.map(tab => (
                <button 
                  key={tab} 
                  className={`tab-btn ${activeTab === tab ? "active" : ""}`} 
                  onClick={() => setActiveTab(tab)}
                  style={{ padding: "12px 24px" }}
                >
                  {tab}
                </button>
              ))}
            </div>

            {/* Recipe Grid */}
            <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill, minmax(280px, 1fr))", gap: "24px" }}>
              {filtered.map(recipe => (
                <div 
                  key={recipe._id} 
                  className="card-hover"
                  onClick={() => { setSelectedRecipe(recipe); setPage("recipe-detail"); }}
                  style={{ background: "var(--white)", borderRadius: "var(--radius-lg)", overflow: "hidden", border: "1px solid var(--border-light)", cursor: "pointer", transition: "var(--transition)" }}
                >
                  <div style={{ position: "relative", height: "180px" }}>
                    <img src={recipe.image} alt={recipe.title} style={{ width: "100%", height: "100%", objectFit: "cover" }} />
                    <span className={`badge ${STATUS_BADGE[recipe.status]}`} style={{ position: "absolute", top: "12px", left: "12px", border: "1px solid rgba(0,0,0,0.05)" }}>
                      ● {recipe.status}
                    </span>
                  </div>
                  <div style={{ padding: "20px" }}>
                    <h3 style={{ fontSize: "16px", fontWeight: "700", color: "var(--text-main)", marginBottom: "4px" }}>{recipe.title}</h3>
                    <p style={{ fontSize: "12px", color: "var(--text-muted)" }}>Updated {recipe.updatedAgo || "recently"}</p>
                  </div>
                  <div style={{ display: "flex", gap: "8px", padding: "0 20px 20px" }}>
                    {[
                      { icon: "✏️", label: "Edit" },
                      { icon: "📊", label: "Stats" },
                      { icon: "🗑️", label: "Delete" }
                    ].map(action => (
                      <button 
                        key={action.label}
                        style={{ 
                          flex: 1, 
                          background: "var(--bg)", 
                          border: "1px solid var(--border-light)", 
                      padding: "8px", 
                      borderRadius: "8px", 
                      fontSize: "14px",
                      transition: "var(--transition)"
                    }}
                    onMouseEnter={e => e.currentTarget.style.background = "rgba(255,49,49,0.05)"}
                    onMouseLeave={e => e.currentTarget.style.background = "var(--bg)"}
                  >
                    {action.icon}
                  </button>
                ))}
              </div>
            </div>
          ))}
          </div>

          {/* New Draft Placeholder */}
          <div style={{ 
            background: "var(--white)", 
            border: "2px dashed var(--border-light)", 
            borderRadius: "var(--radius-lg)", 
            display: "flex", 
            flexDirection: "column", 
            alignItems: "center", 
            justifyContent: "center", 
            minHeight: "300px", 
            padding: "40px",
            textAlign: "center"
          }}>
            <div style={{ width: "56px", height: "56px", background: "var(--bg)", borderRadius: "16px", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "24px", marginBottom: "20px" }}>➕</div>
            <h3 style={{ fontSize: "16px", fontWeight: "700", color: "var(--text-main)", marginBottom: "8px" }}>New Idea?</h3>
            <p style={{ fontSize: "13px", color: "var(--text-muted)", marginBottom: "24px", lineHeight: "1.5" }}>Start drafting your next culinary masterpiece and share it with the world.</p>
            <button className="btn-secondary" style={{ padding: "8px 24px", fontSize: "13px" }} onClick={() => setIsModalOpen(true)}>New Draft</button>
          </div>
          </>
          </div>
        ) : null}
        <CreateRecipeModal 
          isOpen={isModalOpen} 
          onClose={() => setIsModalOpen(false)} 
          onRefresh={fetchMyRecipes} 
        />
        </>
      </main>
    </div>
  );
}
